using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    [TestMethod]
    [DataRow("5551234567")]
    [DataRow("8005551212")]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens(string digits)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.StartsWith("(", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesExpectedPattern()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    [DataRow("5551234567", "(555) 123-4567")]
    [DataRow("8005551212", "(800) 555-1212")]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber(string digits, string expected)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson");

        Assert.Contains("Johnson", result);
    }

    [TestMethod]
    [DataRow("Smith", "Dr.", "Dear Dr. Smith,")]
    [DataRow("Jones", "Ms.", "Dear Ms. Jones,")]
    public void BuildGreeting_WithCustomTitle_ReturnsExpectedGreeting(
        string name, string title, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void BuildGreeting_NullName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_EmptyOrWhitespaceName_ThrowsArgumentException(string name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name));
    }

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlyValidChars()
    {
        var result = _formatter.GenerateSlug("My Post! #1");

        Assert.MatchesRegex(@"^[a-z0-9-]+$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("  Hello World  ");

        Assert.StartsWith("h", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("  Hello World  ");

        Assert.EndsWith("d", result);
    }

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("  My Blog Post!  ", "my-blog-post")]
    [DataRow("C# Is Great", "c-is-great")]
    public void GenerateSlug_VariousTitles_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceOnly_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

    [TestMethod]
    public void FormatCurrency_PositiveAmount_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(10m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(5.50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_Amount_ContainsDecimalPoint()
    {
        var result = _formatter.FormatCurrency(99.9m);

        Assert.Contains(".", result);
    }

    [TestMethod]
    public void FormatCurrency_Amount_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }

    [TestMethod]
    [DataRow("19.99", "$", "$19.99")]
    [DataRow("0.50", "€", "€0.50")]
    [DataRow("1000.00", "£", "£1000.00")]
    public void FormatCurrency_VariousAmounts_ReturnsExpectedFormat(
        string amount, string symbol, string expected)
    {
        var result = _formatter.FormatCurrency(decimal.Parse(amount), symbol);

        Assert.AreEqual(expected, result);
    }
}

